from collections import Counter

def top_k(text, k):
    counts = Counter(text.split())
    return counts.most_common(k)

print(top_k('a b a c a b', 2))
# Output: [('a', 3), ('b', 2)]

from contextlib import contextmanager

@contextmanager
def counting():
    state = {'n': 0}
    def tick():
        state['n'] += 1
    yield tick
    print(f"total: {state['n']}")

with counting() as tick:
    tick(); tick(); tick()
# Output: total: 3
